export const 鎮宅橫損 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    const 連 = (a, b) => {
        const dx = b[0] - a[0], dz = b[1] - a[1], L = Math.hypot(dx, dz), t = 0.4 / L;
        線(p => p.M(X(a[0] + dx * t), Z(a[1] + dz * t)).L(X(b[0] - dx * t), Z(b[1] - dz * t)));
    };
    // 符頭：人字大鏈V二＋散圈行
    連([0.8, 1.0], [3.4, 2.4]);
    連([3.4, 2.4], [6.9, 0.9]);
    圈(0.8, 1.0);
    圈(3.4, 2.4);
    圈(6.9, 0.9);
    連([0.9, 3.0], [3.4, 4.2]);
    連([3.4, 4.2], [5.5, 3.2]);
    圈(0.9, 3.0);
    圈(3.4, 4.2);
    圈(5.5, 3.2);
    for (const [x, z] of [[2.0, 5.3], [4.2, 5.3], [1.4, 6.8], [3.5, 6.8], [4.7, 6.8], [6.5, 6.8]])
        圈(x, z);
    // 目箱＋卄框層
    線(p => p.M(X(0.9), Z(7.7)).L(X(0.9), Z(10.6)));
    線(p => p.M(X(4.0), Z(7.65)).L(X(4.0), Z(10.55)));
    for (const z of [7.7, 9.15, 10.6])
        線(p => p.M(X(0.9), Z(z)).L(X(4.0), Z(z - 0.05)));
    線(p => p.M(X(4.6), Z(7.9)).L(X(6.9), Z(7.85)));
    線(p => p.M(X(5.1), Z(7.9)).L(X(5.1), Z(10.5)));
    線(p => p.M(X(6.9), Z(7.85)).L(X(6.9), Z(10.5)));
    線(p => p.M(X(4.6), Z(9.2)).L(X(6.85), Z(9.15)));
    線(p => p.M(X(4.6), Z(10.5)).L(X(6.9), Z(10.45)));
    // 寬桁
    線(p => p.M(X(0.9), Z(11.15)).L(X(6.9), Z(11.05)), 0.42);
    // 口箱層二（左箱右桁）
    線(p => p.M(X(1.0), Z(13.2)).L(X(1.0), Z(15.9)).L(X(3.9), Z(15.85))
        .L(X(3.9), Z(13.15)).L(X(0.95), Z(13.2)));
    線(p => p.M(X(1.1), Z(14.55)).L(X(3.8), Z(14.5)));
    線(p => p.M(X(4.5), Z(13.5)).L(X(6.9), Z(13.45)));
    線(p => p.M(X(4.5), Z(14.8)).L(X(6.9), Z(14.75)));
    線(p => p.M(X(1.1), Z(16.5)).L(X(1.1), Z(18.7)).L(X(3.6), Z(18.65))
        .L(X(3.6), Z(16.45)).L(X(1.05), Z(16.5)));
    線(p => p.M(X(1.2), Z(17.6)).L(X(3.5), Z(17.55)));
    線(p => p.M(X(4.5), Z(16.7)).L(X(6.8), Z(16.65)));
    線(p => p.M(X(4.5), Z(17.9)).L(X(6.8), Z(17.85)));
    // 右軌
    線(p => p.M(X(6.9), Z(10.5)).L(X(6.9), Z(18.6)));
};
